ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?illustrators a :Illustrator .
    ?childrensbooks a :ChildrensBooks .
    ?childrensbooks p:hasIllustrators ?illustrators .
    ?childrensbooks p:title ?title .
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?illustrators a :Illustrator .
    ?youngadultbooks a :ChildrensBooks .
    ?youngadultbooks p:hasIllustrators ?illustrators .
    ?youngadultbooks p:title ?title .
    ?illustrators p:illustratorName ?illustratorname_f .
    FILTER(STR(?illustratorname_f) = "Jane Smith")
    BIND(?title AS ?o0)
  }
} }
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?illustrators a :Illustrator .
    ?childrensbooks a :ChildrensBooks .
    ?childrensbooks p:hasIllustrators ?illustrators .
    ?childrensbooks p:title ?title .
    ?illustrators p:illustratorName ?illustratorname_f .
    FILTER(STR(?illustratorname_f) = "Jane Smith")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?illustrators a :Illustrator .
    ?youngadultbooks a :ChildrensBooks .
    ?youngadultbooks p:hasIllustrators ?illustrators .
    ?youngadultbooks p:title ?title .
    ?illustrators p:illustratorName ?illustratorname_f .
    FILTER(STR(?illustratorname_f) = "Jane Smith")
    BIND(?title AS ?o0)
  }
} }
}
